import React, { useEffect, useRef, useState } from "react";

const NOTE_WIDTH = 200;
const NOTE_HEIGHT = 150;

const getRandomPosition = () => {
    const x = Math.random() * (window.innerWidth - NOTE_WIDTH);
    const y = Math.random() * (window.innerHeight - NOTE_HEIGHT);
    return { x, y };
};

const loadNotes = () => {
    const saved = localStorage.getItem("notes");
    return saved ? JSON.parse(saved) : [];
};

const saveNotes = (notes) => {
    localStorage.setItem("notes", JSON.stringify(notes));
};

const checkForOverlap = (id, x, y, notes) => {
    return notes.some((note) => {
        if (note.id === id) return false;

        return !(
            x + NOTE_WIDTH < note.x ||
            x > note.x + NOTE_WIDTH ||
            y + NOTE_HEIGHT < note.y ||
            y > note.y + NOTE_HEIGHT
        );
    });
};

const DragDrop = () => {
    const [notes, setNotes] = useState(loadNotes);
    const dragData = useRef(null);
    const noteRefs = useRef({});

    useEffect(() => {
        saveNotes(notes);
    }, [notes]);

    const handleMouseDown = (e, id) => {
        const note = notes.find((n) => n.id === id);

        dragData.current = {
            id,
            offsetX: e.clientX - note.x,
            offsetY: e.clientY - note.y,
            startX: note.x,
            startY: note.y,
        };

        window.addEventListener("mousemove", handleMouseMove);
        window.addEventListener("mouseup", handleMouseUp);
    };

    const handleMouseMove = (e) => {
        const { id, offsetX, offsetY } = dragData.current;

        const newX = e.clientX - offsetX;
        const newY = e.clientY - offsetY;

        setNotes((prev) =>
            prev.map((note) =>
                note.id === id ? { ...note, x: newX, y: newY } : note
            )
        );
    };

    const handleMouseUp = () => {
        const { id, startX, startY } = dragData.current;

        setNotes((prev) => {
            const current = prev.find((n) => n.id === id);

            const hasOverlap = checkForOverlap(id, current.x, current.y, prev);

            if (hasOverlap) {
                return prev.map((note) =>
                    note.id === id ? { ...note, x: startX, y: startY } : note
                );
            }

            return prev;
        });

        window.removeEventListener("mousemove", handleMouseMove);
        window.removeEventListener("mouseup", handleMouseUp);
        dragData.current = null;
    };

    const addNote = () => {
        const position = getRandomPosition();

        const newNote = {
            id: Date.now(),
            text: "New Note",
            ...position,
        };

        setNotes((prev) => [...prev, newNote]);
    };

    return (
        <div>
            <button onClick={addNote}>Add Note</button>

            {notes.map((note) => (
                <div
                    key={note.id}
                    ref={(el) => (noteRefs.current[note.id] = el)}
                    onMouseDown={(e) => handleMouseDown(e, note.id)}
                    style={{
                        position: "absolute",
                        width: NOTE_WIDTH,
                        height: NOTE_HEIGHT,
                        background: "#fffa75",
                        padding: 10,
                        cursor: "grab",
                        left: note.x,
                        top: note.y,
                        boxShadow: "0 2px 8px rgba(0,0,0,0.2)",
                    }}
                >
                    {note.text}
                </div>
            ))}
        </div>
    );
};

export default DragDrop;
